-- ── Monica ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Monica (MonicaHQ) is an open-source personal relationship management (PRM) app that helps people remember and organize details about friends, family, and personal contacts.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted or free hosted plan); paid hosted plan from about $9/month$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Very small (creator-led open-source project with community contributors)$q$, company_size),
  headquarters = COALESCE($q$Montreal, Canada (creator's base; no formal corporate headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$, $q$Portuguese$q$, $q$Italian$q$, $q$Dutch$q$, $q$Chinese$q$, $q$Hebrew$q$]::text[],
  seo_title = COALESCE($q$Monica (MonicaHQ) Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Monica (MonicaHQ) review: the open-source personal CRM for tracking friends and family. See features, pricing, self-hosting, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Monica, also known as MonicaHQ, is an open-source personal relationship management (PRM) application designed to help individuals keep track of the people in their lives — friends, family, and personal contacts — the same way a sales CRM helps a company track customers. It was created by Régis Freyd, a developer based in Montreal, Canada, who first built the tool in June 2016 for personal use to stay in touch with friends living abroad. Freyd open-sourced the project in May 2017, and it went viral on Hacker News, reaching the number one spot on the front page for two consecutive days with roughly 1,100 upvotes, which kickstarted its growth into a widely used open-source project. Monica is built with the Laravel PHP framework and is released under the AGPLv3 open-source license, meaning anyone can self-host it for free with full features and no restrictions. Functionally, Monica lets users log how they met a contact, what matters to that person, when they last talked, and notes for what to ask next time. It supports setting reminders (including recurring reminders) for birthdays or check-ins, defining and visualizing relationships between contacts (a network view), logging gifts, activities, debts, and tasks tied to a person, and journaling entries about your own life. A key differentiator is its privacy-first philosophy: Monica states it will never be ad-supported and does not track users, contrasting with many consumer apps that monetize personal data. Monica is available in two forms. The hosted version, run by the Monica team at app.monicahq.com, offers a free plan limited to around 10 contacts along with data export tools, and a paid plan (roughly 9 dollars per month) that unlocks unlimited contacts, email reminders, data importers, and other advanced features. The self-hosted version, deployable via Docker or a standard LAMP/PHP stack, runs the exact same codebase used in production and includes all features for free — the only cost is the server infrastructure a user chooses to run it on (commonly a 5 to 10 dollar per month VPS). The project has been translated into more than 30 languages through its Crowdin-based open-source translation program, including right-to-left language support such as Hebrew. Monica's target audience includes privacy-conscious individuals, consultants, freelancers, and anyone managing a large personal or professional network who wants more structure than a phone contacts app but doesn't want a corporate sales CRM. It particularly appeals to technically capable users comfortable with self-hosting. Its main competitors in the personal CRM space include Dex (which emphasizes LinkedIn activity monitoring), Cloze (which focuses on email and inbox prioritization), Clay (a polished Mac/iOS-only personal CRM), and newer AI-driven personal CRM apps. Monica differentiates itself primarily through being open-source and self-hostable, giving users complete data ownership and privacy that closed, VC-backed personal CRM apps cannot offer, though this comes at the cost of built-in AI features, automatic data enrichment, and the polish of some proprietary competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3ec2fcab-82e1-40ba-a312-37feb11695e6';

