-- ── Moosend ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Moosend is an email marketing and automation platform offering campaign creation, landing pages, and workflow automation, now owned by Constant Contact.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (tiered by contact count, plus custom Enterprise)$q$, pricing_model),
  starting_price = COALESCE($q$$9/month (Pro plan, 500 subscribers); 30-day free trial available$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Mid-size (operates as part of Constant Contact following its 2025 acquisition)$q$, company_size),
  headquarters = COALESCE($q$Athens, Greece (founded); now operated as part of Constant Contact$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Moosend Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Moosend review: email marketing automation with a drag-and-drop builder, landing pages and workflows. See pricing, features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Moosend is an email marketing and marketing automation platform that provides a drag-and-drop email builder, landing page builder, subscription forms, and workflow automation for businesses of various sizes. It was founded in 2011 in Athens, Greece, by Yannis Psarras and Panos Melissaropoulos. The company built a reputation as a lower-cost, feature-rich alternative to larger email marketing platforms like Mailchimp, particularly appealing to small and mid-sized businesses and agencies. In May 2021, digital experience company Sitecore acquired Moosend for a reported sum of over 200 million dollars, adding AI-powered email marketing automation to Sitecore's broader customer experience product suite and rebranding parts of the product as Sitecore Send. Ownership changed again in mid-2025: Constant Contact, one of the longest-running email marketing platforms, acquired Moosend from Sitecore, with the deal completing around June 6, 2025, bringing Moosend back under a dedicated email marketing company rather than a broader CX/CMS platform. Functionally, Moosend provides a visual drag-and-drop email campaign builder, a landing page builder, embeddable subscription/signup forms, audience segmentation, and detailed campaign reporting and analytics. Its marketing automation engine lets users build multi-step workflows triggered by subscriber behavior (opens, clicks, purchases, form submissions) to send targeted follow-up sequences, abandoned cart emails, and lifecycle campaigns. The platform also includes an AI Writer for generating email copy, transactional email sending, an SMTP server for developers, and add-on options like dedicated sending IPs and custom reporting dashboards for higher-volume senders. Pricing is contact-based and tiered: the Pro plan scales from about 9 dollars per month for up to 500 subscribers up through plans for lists of 1,000,000+ contacts, with unlimited email sends included at every contact tier. Customers can choose monthly billing or save 15 percent with biannual billing or 20 percent with annual billing, and registered nonprofits receive an additional 25 percent discount that stacks with billing-cycle discounts. A 'Moosend+' custom plan layers select enterprise add-ons (dedicated IPs, transactional email, audience discovery, custom dashboards, SSO/SAML) onto the Pro tier for growing teams, while a full Enterprise plan offers custom quotes with a dedicated account manager, priority support, deliverability optimization, and SLAs for large-scale senders. Moosend also offers a pay-as-you-go email credit option for infrequent senders (from 350,000 credits for 350 dollars up to 1,000,000 credits for 1,000 dollars, with credits that never expire), and a 30-day free trial with no credit card required, capped at 1,000 contacts during the trial. Moosend's target audience includes small and mid-sized e-commerce businesses, marketing agencies, bloggers, and growing companies that want Mailchimp-comparable automation features at a lower price point. Its main competitors include Mailchimp, Constant Contact's own legacy product line, ActiveCampaign, GetResponse, and Brevo (formerly Sendinblue). Moosend differentiates itself primarily on price-to-feature ratio, commonly cited as 30 to 50 percent cheaper than Mailchimp at comparable subscriber levels while still offering full automation, landing pages, and transactional email capabilities.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5bf89844-295b-44a9-b875-c4f86ae4f19d';

